import { createStructuredOutput } from 'ai/rsc';
import { z } from 'zod';

const invoiceSchema = z.object({
  invoiceNumber: z.string().min(1),
  totalAmount: z.number().positive(),
  date: z.string().datetime(),
  vendor: z.string().min(1)
});

export async function extractInvoice(document: string) {
  const result = await createStructuredOutput({
    model: openai('gpt-4o'),
    schema: invoiceSchema,
    prompt: `Extract invoice details from: ${document}`
  });
  return result;
}

import { useChat } from 'ai/react';
import { extractInvoice } from './extraction';

export function ExtractionUI({ document }: { document: string }) {
  const { messages, append, isLoading } = useChat({
    body: { document },
    initialMessages: [{ role: 'user', content: 'Extract invoice data' }],
    onResponse: async (response) => {
      const result = await extractInvoice(document);
      append({ role: 'assistant', content: JSON.stringify(result) });
    }
  });
  return <div>{/* Render messages */}</div>;
}

import { generateText } from 'ai';
import { z } from 'zod';

const batchSchema = z.array(invoiceSchema);

export async function extractBatch(documents: string[]) {
  const results = await Promise.all(
    documents.map(async (doc) => {
      const { text } = await generateText({
        model: openai('gpt-4o'),
        prompt: `Extract from: ${doc}`,
        schema: invoiceSchema,
        temperature: 0
      });
      return text;
    })
  );
  return batchSchema.parse(results);
}

import { createStructuredOutput } from 'ai/rsc';

export async function safeExtract(document: string) {
  try {
    return await createStructuredOutput({
      model: openai('gpt-4o'),
      schema: invoiceSchema,
      prompt: document,
      mode: 'json'
    });
  } catch (error) {
    console.error('Extraction failed:', error);
    return {
      invoiceNumber: 'UNKNOWN',
      totalAmount: 0,
      date: new Date().toISOString(),
      vendor: 'UNKNOWN',
      _error: true
    };
  }
}

