import { createVex } from '@vex_dev/sdk/ai';
import { generateText } from 'ai';

const vex = createVex({
  projectId: 'your-project-id',
  apiKey: process.env.VEX_API_KEY!
});

export async function verifiedExtract(document: string) {
  const result = await vex(
    generateText.bind(null, {
      model: openai('gpt-4o'),
      schema: invoiceSchema,
      prompt: `Extract invoice from: ${document}`
    }),
    {
      checks: ['schema_compliance'],
      riskProfile: 'medium',
      context: { document }
    }
  );
  return result.text;
}

import { createVex } from '@vex_dev/sdk/ai';
import { streamText } from 'ai';

const vex = createVex({ projectId: 'your-project-id' });

export async function* verifiedStream(document: string) {
  const stream = await vex(
    streamText({
      model: openai('gpt-4o'),
      schema: invoiceSchema,
      prompt: document
    }),
    {
      checks: ['partial_hallucination'],
      stream: true,
      riskProfile: 'medium'
    }
  );

  for await (const chunk of stream) {
    if (chunk.verified) yield chunk;
  }
}

import { createVex } from '@vex_dev/sdk/ai';

const vex = createVex({ projectId: 'your-project-id' });

export async function verifiedBatch(documents: string[]) {
  const tasks = documents.map((doc, i) =>
    vex(
      extractInvoice(doc),
      {
        taskId: `doc-${i}`,
        checks: ['schema_compliance', 'field_accuracy'],
        riskProfile: 'medium',
        async: true
      }
    )
  );

  const results = await Promise.all(tasks);
  return results.filter(r => r.verified);
}
